import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); 
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState(''); // Añade esto arriba con los otros useState
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  const abortControllerRef = useRef(null);
  const [twoStep, setTwoStep] = useState(false); // Para mostrar el paso 2
  const [otp, setOtp] = useState(''); // El código de 6 dígitos
  const [qrCode, setQrCode] = useState(''); // Imagen del QR
  const [secret2FA, setSecret2FA] = useState(''); // Secreto guardado

  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error(error); } 
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) { 
        setIsLoggedIn(true); 
        setUserRole(res.data.rol); 
      }
    } catch (e) { alert("Usuario o clave incorrectos"); }
  };

  const handleRegister = async () => {
    if (!usuario || !password) return alert("Llena los campos");
    try {
      const res = await axios.post('http://localhost:5000/api/register', { 
       email, usuario, clave: password, rol: nuevoRol 
      });
      if (res.data.success) {
        alert("¡Cuenta creada!");
        setAuthMode('login');
      }
    } catch (e) { alert("Error al registrar"); }
  };

  const guardarProducto = async () => {
    try {
      await axios.post('http://localhost:5000/api/productos', {
        nombre: nuevoProd.nombre,
        stock: Number(nuevoProd.stock),
        precio_venta: Number(nuevoProd.precio_venta)
      });
      setShowForm(false);
      cargarDatos();
      setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    } catch (e) { alert("Error al guardar"); }
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Eliminar?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-8 rounded-[40px] shadow-2xl w-full max-w-sm border border-gray-700">
          <div className="text-center mb-8">
            <h2 className="text-3xl font-bold text-white uppercase tracking-tighter">
              {authMode === 'login' ? 'Bienvenido' : authMode === 'register' ? 'Registro' : 'Recuperar'}
            </h2>
            <div className="w-12 h-1 bg-[#00c984] mx-auto rounded-full mt-2"></div>
          </div>

          <div className="space-y-4">
            {authMode !== 'recovery' && (
              <input className="w-full bg-[#444c56] text-white px-5 py-3 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
            )}
            {authMode === 'register' && (
              <select className="w-full bg-[#444c56] text-white px-5 py-3 rounded-2xl outline-none" value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
                <option value="vendedor">Vendedor</option>
                <option value="admin">Administrador</option>
              </select>
            )}
            {authMode !== 'recovery' && (
              <input type="password" title="Contraseña" className="w-full bg-[#444c56] text-white px-5 py-3 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
            )}
            {authMode === 'recovery' && (
              <input className="w-full bg-[#444c56] text-white px-5 py-3 rounded-2xl outline-none" placeholder="Correo de recuperación" />
            )}

            <button className="w-full bg-[#00c984] text-white font-bold py-4 rounded-2xl hover:brightness-110 active:scale-95 transition shadow-lg" 
              onClick={authMode === 'login' ? handleLogin : authMode === 'register' ? handleRegister : () => alert("Correo enviado")}>
              {authMode === 'login' ? 'Entrar' : authMode === 'register' ? 'Crear Cuenta' : 'Recuperar'}
            </button>

            <div className="flex justify-between text-[10px] text-gray-400 font-bold uppercase tracking-widest px-2 cursor-pointer">
              <span onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                {authMode === 'login' ? 'Registro' : 'Login'}
              </span>
              {authMode === 'login' && (
                <span onClick={() => setAuthMode('recovery')}>¿Olvidaste clave?</span>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} busqueda={busqueda} handleBusquedaChange={handleBusquedaChange} />
      {loading && <div className="h-1 w-full bg-[#ffc220] animate-pulse"></div>}

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {view === "dashboard" ? (
          <div className="grid grid-cols-2 md:grid-cols-3 gap-3 md:gap-6">
            <div className="bg-white p-6 border rounded-[30px] shadow-sm text-center">
              <p className="text-[10px] text-gray-400 font-bold uppercase mb-2">Productos</p>
              <p className="text-3xl font-black text-[#0071ce]">{stats.total_productos}</p>
            </div>
            <div className="bg-white p-6 border rounded-[30px] shadow-sm text-center">
              <p className="text-[10px] text-red-400 font-bold uppercase mb-2 tracking-tighter">Bajo Stock</p>
              <p className="text-3xl font-black text-red-500">{stats.bajo_stock}</p>
            </div>
            <div className="bg-white p-6 border rounded-[30px] shadow-sm text-center col-span-2 md:col-span-1">
              <p className="text-[10px] text-gray-400 font-bold uppercase mb-2">Valor</p>
              <p className="text-3xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
            </div>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
                <h2 className="text-xl font-black uppercase text-[#004f91]">Mi Inventario</h2>
                <button onClick={() => setShowForm(!showForm)} className="bg-[#0071ce] text-white px-6 py-2 rounded-full font-black text-xs">
                    {showForm ? 'Cerrar' : '+ Nuevo'}
                </button>
            </div>
            {showForm && (
              <div className="bg-white p-6 rounded-[30px] border-2 border-dashed grid grid-cols-1 md:grid-cols-4 gap-3">
                  <input className="p-3 bg-gray-50 rounded-2xl outline-none" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                  <input className="p-3 bg-gray-50 rounded-2xl outline-none" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                  <input className="p-3 bg-gray-50 rounded-2xl outline-none" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                  <button onClick={guardarProducto} className="bg-[#ffc220] text-[#004f91] font-black rounded-2xl py-3">GUARDAR</button>
              </div>
            )}
            <div className="bg-white border rounded-[30px] overflow-hidden shadow-sm overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-gray-100 text-[10px] font-black uppercase text-gray-400">
                      <tr><th className="p-4">Producto</th><th className="p-4">Stock</th><th className="p-4">Precio</th><th className="p-4">Acciones</th></tr>
                  </thead>
                  <tbody className="divide-y text-sm">
                      {productos.map(p => (
                      <tr key={p.id} className="hover:bg-blue-50/50 transition">
                          <td className="p-4 font-black text-[#004f91]">{p.nombre}</td>
                          <td className="p-4"><span className={`px-2 py-1 rounded-full font-black ${p.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>{p.stock} UNID</span></td>
                          <td className="p-4 font-black">${p.precio_venta}</td>
                          <td className="p-4 space-x-4"><button onClick={() => eliminar(p.id)}>🗑️</button></td>
                      </tr>
                      ))}
                  </tbody>
                </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
